import { useState, useCallback, useRef } from 'react';
import { products, categories, getCategoryColor } from '../data/products';
import { analyticsAPI, localCart, localEvents } from '../services/api';
import { useAuth } from '../context/AuthContext';

const ProductsPage = ({ onToast }) => {
  const { user } = useAuth();
  const [category, setCategory] = useState('All');
  const [search,   setSearch]   = useState('');
  const [modal,    setModal]    = useState(null);

  // sessionId stable for the lifetime of the component
  const sessionId = useRef(
    sessionStorage.getItem('u_session') || (() => {
      const id = 'sess_' + Math.random().toString(36).slice(2);
      sessionStorage.setItem('u_session', id);
      return id;
    })()
  ).current;

  // ── Track event to local store + server ────────────────────────────────────
  const track = useCallback(async (product, actionType) => {
    const ev = {
      sessionId,
      userId:      user?.id,
      productId:   product.id,
      productName: product.name,
      category:    product.category,
      price:       product.price,
      emoji:       product.emoji,
      brand:       product.brand,
      actionType,
    };
    localEvents.add({ ...ev, timestamp: new Date().toISOString() });
    window.dispatchEvent(new Event('eventsUpdated'));
    try { await analyticsAPI.track(ev); } catch {}
  }, [user, sessionId]);

  // ── View product (opens modal + tracks view) ───────────────────────────────
  const viewProduct = (p) => {
    setModal(p);
    track(p, 'product_viewed');
  };

  // ── Add to cart ────────────────────────────────────────────────────────────
  const addToCart = (p) => {
    const cart = localCart.get();
    const existing = cart.find(i => i.id === p.id);
    if (existing) existing.quantity++;
    else cart.push({ ...p, quantity: 1 });
    localCart.set(cart);
    window.dispatchEvent(new Event('cartUpdated'));
    track(p, 'add_to_cart');
    onToast?.(`🛒 ${p.name} added to cart`, 'success');
  };

  // ── Filtered product list ──────────────────────────────────────────────────
  const filtered = products.filter(p =>
    (category === 'All' || p.category === category) &&
    (p.name.toLowerCase().includes(search.toLowerCase()) ||
     p.brand.toLowerCase().includes(search.toLowerCase()))
  );

  return (
    <div>

      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-4 flex-wrap gap-2">
        <div>
          <h4 className="fw-bold mb-1">🛍️ Products</h4>
          <p className="text-muted small mb-0">Browse {products.length} products</p>
        </div>
        <input
          type="text"
          className="form-control"
          placeholder="🔍 Search by name or brand..."
          value={search}
          onChange={e => setSearch(e.target.value)}
          style={{ maxWidth: 260 }}
        />
      </div>

      {/* Category tabs */}
      <div className="d-flex gap-2 mb-4 flex-wrap">
        {categories.map(c => (
          <button
            key={c}
            onClick={() => setCategory(c)}
            className={`btn btn-sm fw-semibold ${category === c ? 'btn-dark' : 'btn-outline-secondary'}`}
          >
            {c}
            <span className="badge bg-secondary ms-1">
              {c === 'All' ? products.length : products.filter(p => p.category === c).length}
            </span>
          </button>
        ))}
      </div>

      {/* No results */}
      {filtered.length === 0 && (
        <div className="text-center py-5 text-muted">
          <div style={{ fontSize: '3rem' }}>🔍</div>
          <p className="mt-2">No products found for "<strong>{search}</strong>"</p>
        </div>
      )}

      {/* Product grid */}
      <div className="row g-3">
        {filtered.map(p => (
          <div key={p.id} className="col-xl-3 col-lg-4 col-md-6 col-12">
            <div
              className="h-100 p-3 rounded-4 position-relative d-flex flex-column"
              style={{
                background: 'linear-gradient(145deg,#1f1f1f,#2c2c2c)',
                color: 'white',
                border: '1px solid rgba(255,255,255,0.08)',
                transition: 'transform 0.25s, box-shadow 0.25s',
                cursor: 'pointer',
              }}
              onMouseEnter={e => {
                e.currentTarget.style.transform = 'translateY(-6px) scale(1.02)';
                e.currentTarget.style.boxShadow = '0 12px 32px rgba(0,0,0,0.4)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = 'none';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              {/* Category badge */}
              <span
                className={`badge position-absolute top-0 end-0 m-2 bg-${getCategoryColor(p.category)}`}
                style={{ fontSize: '0.65rem' }}
              >
                {p.category}
              </span>

              {/* Emoji */}
              <div className="text-center mb-2" style={{ fontSize: '2.8rem' }}>
                {p.emoji}
              </div>

              {/* Name */}
              <h6 className="fw-bold text-center mb-1" style={{ fontSize: '0.85rem' }}>
                {p.name}
              </h6>

              {/* Brand */}
              <div className="text-center small text-secondary mb-1">{p.brand}</div>

              {/* Specs */}
              <p className="small text-center mb-2" style={{ color: 'rgba(255,255,255,0.55)', fontSize: '0.75rem', flexGrow: 1 }}>
                {p.specs}
              </p>

              {/* Rating */}
              <div className="text-center mb-2">
                <span style={{ color: '#ffc107', fontSize: '0.75rem' }}>
                  {'★'.repeat(Math.round(p.rating))}{'☆'.repeat(5 - Math.round(p.rating))}
                </span>
                <span className="text-secondary ms-1" style={{ fontSize: '0.7rem' }}>{p.rating}</span>
              </div>

              {/* Price */}
              <div className="text-center fw-bold text-warning mb-2" style={{ fontSize: '1.1rem' }}>
                ₹{p.price.toLocaleString('en-IN')}
              </div>

              {/* Buttons */}
              <div className="d-grid gap-1">
                <button
                  className="btn btn-outline-light btn-sm"
                  onClick={() => viewProduct(p)}
                >
                  👁️ View Details
                </button>
                <button
                  className="btn btn-warning btn-sm fw-bold"
                  onClick={() => addToCart(p)}
                >
                  🛒 Add to Cart
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Product Modal */}
      {modal && (
        <div
          className="modal show d-block"
          style={{ background: 'rgba(0,0,0,0.65)' }}
          onClick={() => setModal(null)}
        >
          <div
            className="modal-dialog modal-dialog-centered"
            onClick={e => e.stopPropagation()}
          >
            <div className="modal-content border-0 shadow-lg">

              <div className="modal-header border-0 pb-0">
                <h5 className="modal-title fw-bold">{modal.name}</h5>
                <button className="btn-close" onClick={() => setModal(null)} />
              </div>

              <div className="modal-body text-center px-4">
                <div style={{ fontSize: '5rem' }}>{modal.emoji}</div>

                <span className={`badge bg-${getCategoryColor(modal.category)} mb-2`}>
                  {modal.category}
                </span>

                <h5 className="fw-bold mt-2">{modal.name}</h5>

                <p className="text-muted small">{modal.brand}</p>

                <div className="alert alert-light py-2 small mb-3">
                  🔧 {modal.specs}
                </div>

                {/* Rating */}
                <div className="mb-3">
                  <span style={{ color: '#ffc107', fontSize: '1.1rem' }}>
                    {'★'.repeat(Math.round(modal.rating))}{'☆'.repeat(5 - Math.round(modal.rating))}
                  </span>
                  <span className="text-muted ms-2 small">{modal.rating} / 5</span>
                </div>

                <div className="fw-bold text-success fs-4">
                  ₹{modal.price.toLocaleString('en-IN')}
                </div>
              </div>

              <div className="modal-footer border-0 pt-0">
                <button className="btn btn-outline-secondary" onClick={() => setModal(null)}>
                  Close
                </button>
                <button
                  className="btn btn-warning fw-bold px-4"
                  onClick={() => { addToCart(modal); setModal(null); }}
                >
                  🛒 Add to Cart
                </button>
              </div>

            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default ProductsPage;
